141→internal class OptionalFormatStructure<in T>(
142→    val onZero: String,
143→    val format: FormatStructure<T>,
144→) : NonConcatenatedFormatStructure<T> {
145→    override fun toString(): String = "Optional($onZero, $format)"
146→
147→    private val fields = basicFormats(format).map { it.field }.distinct().map { field ->
148→        PropertyWithDefault.fromField(field)
149→    }
150→
151→    override fun equals(other: Any?): Boolean =
152→        other is OptionalFormatStructure<*> && onZero == other.onZero && format == other.format
153→
154→    override fun hashCode(): Int = 31 * onZero.hashCode() + format.hashCode()
155→
156→    override fun parser(): ParserStructure<T> = ParserStructure(
157→        operations = emptyList(),
158→        followedBy = listOf(
159→            format.parser(),
160→            listOf(
161→                ConstantFormatStructure<T>(onZero).parser(),
162→                ParserStructure(
163→                    if (fields.isEmpty()) {
164→                        emptyList()
165→                    } else {
166→                        listOf(
167→                            UnconditionalModification {
168→                                for (field in fields) {
169→                                    field.assignDefault(it)
170→                                }
171→                            }
172→                        )
173→                    },
174→                    emptyList()
175→                )
176→            ).concat()
177→        )
178→    )
179→
180→    override fun formatter(): FormatterStructure<T> {
181→        val formatter = format.formatter()
182→        val predicate = conjunctionPredicate(fields.map { it.isDefaultComparisonPredicate() })
183→        return if (predicate is Truth) {
184→            ConstantStringFormatterStructure(onZero)
185→        } else {
186→            ConditionalFormatter(
187→                listOf(
188→                    predicate::test to ConstantStringFormatterStructure(onZero),
189→                    Truth::test to formatter
190→                )
191→            )
192→        }
193→    }
194→
195→    private class PropertyWithDefault<in T, E> private constructor(
196→        private val accessor: Accessor<T, E>,
197→        private val defaultValue: E
198→    ) {
199→        companion object {
200→            fun <T, E> fromField(field: FieldSpec<T, E>): PropertyWithDefault<T, E> {
201→                val default = field.defaultValue
202→                require(default != null) {
203→                    "The field '${field.name}' does not define a default value"
204→                }
205→                return PropertyWithDefault(field.accessor, default)
206→            }
207→        }
208→
209→        inline fun assignDefault(target: T) {
210→            accessor.trySetWithoutReassigning(target, defaultValue)
211→        }
212→
213→        inline fun isDefaultComparisonPredicate() = ComparisonPredicate(defaultValue, accessor::getter)
214→    }
215→}
