package kotlinx.datetime.test.format

import kotlinx.datetime.*
import kotlinx.datetime.format.*
import kotlin.test.*

/**
 * Tests that the parsing API rejects non-ASCII digits.
 * 
 * Previously, the parser accepted any Unicode digit character because it used
 * Char.isDigit() which returns true for non-ASCII digits. The fix ensures
 * only ASCII digits ('0'-'9') are accepted.
 */
class NonAsciiDigitParsingTest {

    @Test
    fun testRejectsFullWidthDigits() {
        // Fullwidth digits (U+FF10 - U+FF19): ０１２３４５６７８９
        val fullWidthInput = "２０２４０９０６"
        assertFailsWith<IllegalArgumentException> {
            LocalDate.parse(fullWidthInput, LocalDate.Formats.ISO_BASIC)
        }
    }

    @Test
    fun testRejectsArabicIndicDigits() {
        // Arabic-Indic digits (U+0660 - U+0669): ٠١٢٣٤٥٦٧٨٩
        val arabicIndicInput = "٢٠٢٤٠٩٠٦"
        assertFailsWith<IllegalArgumentException> {
            LocalDate.parse(arabicIndicInput, LocalDate.Formats.ISO_BASIC)
        }
    }

    @Test
    fun testRejectsMixedNonAsciiDigits() {
        // Mix of ASCII, fullwidth (０, ４) and Arabic-Indic (٠, ٩) digits: "2０2４٠٩０６"
        // This is the example from the issue report
        val mixedInput = "2０2４٠٩０６"
        assertFailsWith<IllegalArgumentException> {
            LocalDate.parse(mixedInput, LocalDate.Formats.ISO_BASIC)
        }
    }

    @Test
    fun testAcceptsAsciiDigits() {
        // Valid ASCII input should still work
        val asciiInput = "20240906"
        val result = LocalDate.parse(asciiInput, LocalDate.Formats.ISO_BASIC)
        assertEquals(LocalDate(2024, 9, 6), result)
    }

    @Test
    fun testIsoFormatRejectsNonAsciiDigits() {
        // Test with ISO format (with dashes)
        val fullWidthInput = "２０２４-０９-０６"
        assertFailsWith<IllegalArgumentException> {
            LocalDate.parse(fullWidthInput, LocalDate.Formats.ISO)
        }
    }

    @Test
    fun testLocalTimeRejectsNonAsciiDigits() {
        // Test LocalTime parsing
        val fullWidthInput = "１２:３０:４５"
        assertFailsWith<IllegalArgumentException> {
            LocalTime.parse(fullWidthInput, LocalTime.Formats.ISO)
        }
    }

    @Test
    fun testLocalDateTimeRejectsNonAsciiDigits() {
        // Test LocalDateTime parsing
        val fullWidthInput = "２０２４-０９-０６T１２:３０:４５"
        assertFailsWith<IllegalArgumentException> {
            LocalDateTime.parse(fullWidthInput, LocalDateTime.Formats.ISO)
        }
    }

    @Test
    fun testInstantRejectsNonAsciiDigits() {
        // Test Instant parsing
        val fullWidthInput = "２０２４-０９-０６T１２:３０:４５Z"
        assertFailsWith<IllegalArgumentException> {
            Instant.parse(fullWidthInput)
        }
    }

    @Test
    fun testUtcOffsetRejectsNonAsciiDigits() {
        // Test UtcOffset parsing
        val fullWidthInput = "+０５:３０"
        assertFailsWith<IllegalArgumentException> {
            UtcOffset.parse(fullWidthInput)
        }
    }
}
